const updateGroup = `-- name: UpdateGroup :one
UPDATE "group" SET
    name = COALESCE($2, name),
    announcement = COALESCE($3, announcement),
    updated_at = now()
WHERE id = $1
RETURNING id, workspace_id, name, avatar_url, announcement, created_by_type, created_by_id, status, created_at, updated_at
`

type UpdateGroupParams struct {
	ID           pgtype.UUID `json:"id"`
	Name         pgtype.Text `json:"name"`
	Announcement pgtype.Text `json:"announcement"`
}

func (q *Queries) UpdateGroup(ctx context.Context, arg UpdateGroupParams) (Group, error) {
	row := q.db.QueryRow(ctx, updateGroup, arg.ID, arg.Name, arg.Announcement)
	var i Group
	err := row.Scan(
		&i.ID,
		&i.WorkspaceID,
		&i.Name,
		&i.AvatarUrl,
		&i.Announcement,
		&i.CreatedByType,
		&i.CreatedByID,
		&i.Status,
		&i.CreatedAt,
		&i.UpdatedAt,
	)
	return i, err
}
